   396→// Searches from the beginning of |keyframes| for a Keyframe object with the
   397→// specified offset and timing function. If none is found, a new Keyframe object
   398→// with the specified |offset| and |timingFunction| will be prepended to
   399→// |keyframes|.
   400→//
   401→// @param keyframes  An array of Keyframe objects, sorted by offset.
   402→//                   The first Keyframe in the array, if any, MUST have an
   403→//                   offset greater than or equal to |offset|.
   404→// @param offset  The offset to search for, or, if no suitable Keyframe is
   405→//                found, the offset to use for the created Keyframe.
   406→//                Must be a floating point number in the range [0.0, 1.0].
   407→// @param timingFunction  The timing function to match, or, if no suitable
   408→//                        Keyframe is found, to set on the created Keyframe.
   409→// @param composition  The composition to match, or, if no suitable Keyframe is
   410→//                     found, to set on the created Keyframe.
   411→//
   412→// @returns  The matching or created Keyframe.
   413→mozilla::Keyframe* Gecko_GetOrCreateKeyframeAtStart(
   414→    nsTArray<mozilla::Keyframe>* keyframes, float offset,
   415→    const mozilla::StyleComputedTimingFunction* timingFunction,
   416→    const mozilla::dom::CompositeOperationOrAuto composition);
   417→
   418→// As with Gecko_GetOrCreateKeyframeAtStart except that this method will search
   419→// from the beginning of |keyframes| for a Keyframe with matching timing
   420→// function, composition, and an offset of 0.0.
   421→// Furthermore, if a matching Keyframe is not found, a new Keyframe will be
   422→// inserted after the *last* Keyframe in |keyframes| with offset 0.0.
   423→mozilla::Keyframe* Gecko_GetOrCreateInitialKeyframe(
   424→    nsTArray<mozilla::Keyframe>* keyframes,
   425→    const mozilla::StyleComputedTimingFunction* timingFunction,
   426→    const mozilla::dom::CompositeOperationOrAuto composition);
   427→
   428→// As with Gecko_GetOrCreateKeyframeAtStart except that this method will search
