   430→// composition, and an offset of 1.0. If a matching Keyframe is not found, a new
   431→// Keyframe will be appended to the end of |keyframes|.
   432→mozilla::Keyframe* Gecko_GetOrCreateFinalKeyframe(
   433→    nsTArray<mozilla::Keyframe>* keyframes,
